import React from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.js';

function LoginPage() {
  const { login, isAuthenticated } = useAuth();

  // If user is already authenticated, redirect to dashboard
  if (isAuthenticated) {
    return <Navigate to="/dashboard" />;
  }

  const handleGoogleLogin = () => {
    login();
  };

  return (
    <div className="flex justify-center items-center min-h-[70vh] p-5 rtl">
      <div className="bg-white rounded-xl shadow-xl p-10 max-w-md w-full text-center">
        <h1 className="text-2xl font-bold text-gray-800 mb-4">ورود به سامانه</h1>
        <p className="text-gray-600 mb-8">برای دسترسی به اطلاعات بورسی، وارد شوید.</p>

        <button 
          onClick={handleGoogleLogin} 
          className="flex items-center justify-center w-full py-3 px-5 bg-white border border-gray-300 rounded-md text-gray-700 font-medium hover:bg-gray-50 transition duration-300"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" className="ml-3 fill-[#4285F4]">
            <path d="M12.545,10.239v3.821h5.445c-0.712,2.315-2.647,3.972-5.445,3.972c-3.332,0-6.033-2.701-6.033-6.032s2.701-6.032,6.033-6.032c1.498,0,2.866,0.549,3.921,1.453l2.814-2.814C17.503,2.988,15.139,2,12.545,2C7.021,2,2.543,6.477,2.543,12s4.478,10,10.002,10c8.396,0,10.249-7.85,9.426-11.748L12.545,10.239z"/>
          </svg>
          ورود با گوگل
        </button>
      </div>
    </div>
  );
}

export default LoginPage;
